// Ukázková React komponenta — součást kitu
// Každý kit může mít libovolný počet souborů

import styles from './StatusBadge.module.css';

// Komponenta přijímá prop "status" a zobrazí barevný badge
export function StatusBadge({ status = 'idle', label }) {
  // Každý stav má jiné CSS
  const variants = {
    idle:    { text: label || 'Čeká',     cls: styles.idle },
    loading: { text: label || 'Načítám',  cls: styles.loading },
    success: { text: label || 'Hotovo',   cls: styles.success },
    error:   { text: label || 'Chyba',    cls: styles.error },
  };

  const variant = variants[status] ?? variants.idle;

  return (
    <span className={`${styles.badge} ${variant.cls}`}>
      {/* Tečka — barva se mění podle stavu */}
      <span className={styles.dot} />
      {variant.text}
    </span>
  );
}

// Ukázka použití:
//
// <StatusBadge status="loading" />
// <StatusBadge status="success" label="Uloženo" />
// <StatusBadge status="error"   label="Selhalo" />

/* CSS Modules — třídy jsou automaticky unikátní, takže .badge nezasáhne zbytek app */

.badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 3px 10px;
  border-radius: 99px;   /* pill tvar */
  font-size: 12px;
  font-weight: 600;
  border: 1px solid currentColor;
  white-space: nowrap;
}

/* Malá tečka vlevo */
.dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: currentColor;
  flex-shrink: 0;
}

/* ── Varianty stavu ── */

.idle {
  color: #6b7280;
  background: #f3f4f6;
  border-color: #e5e7eb;
}

.loading {
  color: #2563eb;
  background: #eff6ff;
  border-color: #bfdbfe;
  /* Pulzující animace */
  animation: pulse 1.5s ease-in-out infinite;
}

.success {
  color: #16a34a;
  background: #f0fdf4;
  border-color: #bbf7d0;
}

.error {
  color: #dc2626;
  background: #fef2f2;
  border-color: #fecaca;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0.6; }
}
